import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion'; // Install framer-motion
import { 
  ShoppingBag, Mail, Lock, Eye, EyeOff, 
  Smartphone, KeyRound, ChevronRight, ArrowLeft 
} from 'lucide-react';
import { mongoAuthAPI, getUserIdFromToken } from '../api';
import { formatTime } from '../utils/helpers';

const LoginPage = ({ setCurrentPage, setUser, setError, error, loading, setLoading }) => {
  const [showPassword, setShowPassword] = useState(false);
  const [loginData, setLoginData] = useState({ email: '', password: '' });
  const [loginRole, setLoginRole] = useState('Customer');
  const [loginMethod, setLoginMethod] = useState('email');

  // OTP States
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [otpSent, setOtpSent] = useState(false);
  const [otpTimer, setOtpTimer] = useState(0);
  const [canResend, setCanResend] = useState(false);

  const [emailForOtp, setEmailForOtp] = useState('');
  const [emailOtp, setEmailOtp] = useState(['', '', '', '', '', '']);
  const [emailOtpSent, setEmailOtpSent] = useState(false);

  useEffect(() => {
    if (otpTimer > 0) {
      const timer = setTimeout(() => setOtpTimer(otpTimer - 1), 1000);
      return () => clearTimeout(timer);
    } else if (otpTimer === 0 && (otpSent || emailOtpSent)) {
      setCanResend(true);
    }
  }, [otpTimer, otpSent, emailOtpSent]);

  // Logic handlers (Keeping your existing logic intact)
  const handleLogin = async () => { /* your existing handleLogin code */ };
  const handleRequestOTP = async () => { /* your existing handleRequestOTP code */ };
  // ... rest of your existing logic functions ...

  const containerVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.6, ease: "easeOut" } }
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] flex items-center justify-center p-4 md:p-6 font-sans overflow-hidden relative">
      {/* Decorative Animated Background Elements */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-100 rounded-full blur-[120px] opacity-60 animate-pulse"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-100 rounded-full blur-[120px] opacity-60"></div>

      <motion.div 
        variants={containerVariants}
        initial="hidden"
        animate="visible"
        className="max-w-[1100px] w-full grid md:grid-cols-2 bg-white rounded-[32px] shadow-[0_20px_50px_rgba(0,0,0,0.05)] overflow-hidden border border-gray-100 relative z-10"
      >
        {/* Left Side: Brand & Marketing */}
        <div className="hidden md:flex flex-col justify-between p-12 bg-gradient-to-br from-indigo-600 to-blue-700 text-white relative overflow-hidden">
          <div className="relative z-10">
            <div className="flex items-center gap-2 mb-12">
              <div className="p-2 bg-white/20 rounded-lg backdrop-blur-md">
                <ShoppingBag className="w-6 h-6" />
              </div>
              <span className="text-xl font-bold tracking-tight">LUXE MARKET</span>
            </div>
            <h2 className="text-4xl font-bold leading-tight mb-6">
              Discover the <br /> 
              <span className="text-blue-200">Newest Trends</span> <br />
              in Fashion.
            </h2>
            <p className="text-blue-100 text-lg">Join over 2 million shoppers worldwide and get exclusive early access to our seasonal drops.</p>
          </div>

          <div className="relative z-10 mt-8 p-6 bg-white/10 rounded-2xl border border-white/20 backdrop-blur-sm">
            <p className="italic text-sm text-blue-50">"The best shopping experience I've had online. Fast, secure, and always stylish."</p>
            <p className="mt-4 font-bold text-sm">— Sarah J., Platinum Member</p>
          </div>

          {/* Abstract Shape */}
          <div className="absolute right-[-20%] top-[20%] w-64 h-64 border-[30px] border-white/10 rounded-full"></div>
        </div>

        {/* Right Side: Login Form */}
        <div className="p-8 md:p-12 lg:p-16 flex flex-col justify-center">
          <div className="mb-8">
            <motion.h1 
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              className="text-3xl font-bold text-gray-900"
            >
              Welcome Back
            </motion.h1>
            <p className="text-gray-500 mt-2">Enter your details to access your wardrobe.</p>
          </div>

          {/* Method Selector - Pill Style */}
          <div className="flex p-1 bg-gray-100 rounded-2xl mb-8">
            {['email', 'mobile', 'emailOtp'].map((method) => (
              <button
                key={method}
                onClick={() => setLoginMethod(method)}
                className={`flex-1 py-2.5 text-sm font-semibold rounded-xl transition-all ${
                  loginMethod === method 
                  ? 'bg-white text-blue-600 shadow-sm' 
                  : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                {method.charAt(0).toUpperCase() + method.slice(1)}
              </button>
            ))}
          </div>

          <AnimatePresence mode="wait">
            <motion.div
              key={loginMethod}
              initial={{ opacity: 0, x: 10 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -10 }}
              transition={{ duration: 0.2 }}
            >
              {error && (
                <motion.div 
                  initial={{ scale: 0.95 }}
                  animate={{ scale: 1 }}
                  className="mb-6 p-4 bg-red-50 border border-red-100 text-red-600 rounded-xl text-sm font-medium flex items-center gap-2"
                >
                  <div className="w-1.5 h-1.5 bg-red-600 rounded-full animate-ping" />
                  {error}
                </motion.div>
              )}

              {/* Standard Password Login */}
              {loginMethod === 'email' && (
                <form className="space-y-4" onSubmit={(e) => { e.preventDefault(); handleLogin(); }}>
                  <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Email Address</label>
                    <div className="relative group">
                      <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-blue-500 transition-colors" />
                      <input 
                        type="email" 
                        className="w-full pl-12 pr-4 py-3.5 bg-gray-50 border border-gray-100 rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                        placeholder="name@example.com"
                        value={loginData.email}
                        onChange={(e) => setLoginData({ ...loginData, email: e.target.value })}
                      />
                    </div>
                  </div>

                  <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Password</label>
                    <div className="relative group">
                      <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 group-focus-within:text-blue-500 transition-colors" />
                      <input 
                        type={showPassword ? "text" : "password"}
                        className="w-full pl-12 pr-12 py-3.5 bg-gray-50 border border-gray-100 rounded-2xl focus:bg-white focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all outline-none"
                        placeholder="••••••••"
                        value={loginData.password}
                        onChange={(e) => setLoginData({ ...loginData, password: e.target.value })}
                      />
                      <button 
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                      >
                        {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                      </button>
                    </div>
                  </div>

                  <div className="flex items-center justify-between py-2">
                    <label className="flex items-center gap-2 cursor-pointer">
                      <input type="checkbox" className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                      <span className="text-sm text-gray-500">Remember me</span>
                    </label>
                    <button type="button" className="text-sm font-semibold text-blue-600 hover:underline">Forgot password?</button>
                  </div>

                  <button
                    disabled={loading}
                    className="w-full py-4 bg-gray-900 hover:bg-black text-white rounded-2xl font-bold shadow-lg shadow-gray-200 transition-all transform active:scale-[0.98] flex items-center justify-center gap-2"
                  >
                    {loading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : "Sign In"}
                    {!loading && <ChevronRight size={20} />}
                  </button>
                </form>
              )}

              {/* Other login methods would follow a similar structure here */}
            </motion.div>
          </AnimatePresence>

          <div className="mt-10 text-center">
            <p className="text-gray-500">
              Don't have an account?{' '}
              <button 
                onClick={() => setCurrentPage('register')}
                className="font-bold text-gray-900 hover:text-blue-600 transition-colors"
              >
                Sign up for free
              </button>
            </p>
          </div>

          <button 
            onClick={() => setCurrentPage('home')}
            className="mt-8 flex items-center justify-center gap-2 text-sm text-gray-400 hover:text-gray-600 transition-colors group"
          >
            <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" />
            Back to Shop
          </button>
        </div>
      </motion.div>
    </div>
  );
};

export default LoginPage;
